+fn auth_missing_credential_dispatch(
+    subcommand: &str,
+    connector: &str,
+    store: &CredentialStore,
+) -> DispatchOutcome {
+    DispatchOutcome {
+        payload: json!({
+            "status": "error",
+            "command": "auth",
+            "subcommand": subcommand,
